import React, { useEffect, useState } from "react";
import axios from "axios";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import {
  Card,
  Typography,
  Select,
  Button,
  Input,
  Upload,
  Row,
  Col,
  Form,
  message,
} from "antd";
import { UploadOutlined } from "@ant-design/icons";

const { Title, Text } = Typography;
const { TextArea } = Input;
const { Option } = Select;

const FacultyTaskManager = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCourse, setSelectedCourse] = useState("");
  const [taskTitle, setTaskTitle] = useState("");
  const [taskDescription, setTaskDescription] = useState("");
  const [assignmentFile, setAssignmentFile] = useState(null);

  useEffect(() => {
    const fetchCourses = async () => {
      try {
        const facultyUser = JSON.parse(localStorage.getItem("user") || "{}");
        const facultyEmail = facultyUser?.universityEmail || facultyUser?.email;

        const response = await axios.get(
          "http://localhost:65000/api/faculty-courses/courses",
          { params: { universityEmail: facultyEmail } }
        );

        if (response.data.success) {
          const activeCourses = response.data.courses.filter(
            (c) => c.teachingStatus === "in-progress" && c.isActive
          );
          setCourses(activeCourses);
        } else {
          toast.error(response.data.message || "Failed to load courses");
        }
      } catch (err) {
        toast.error("Error fetching courses: " + err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchCourses();
  }, []);

  const handleFileChange = (file) => {
    setAssignmentFile(file.file || file);
    return false; // prevent automatic upload
  };

  const handleRemoveFile = () => setAssignmentFile(null);

  const handleSubmit = async () => {
    if (!selectedCourse) return message.error("Please select a course");
    if (!taskTitle.trim()) return message.error("Task title cannot be empty");
    if (!taskDescription.trim())
      return message.error("Task description cannot be empty");

    try {
      const [codeNamePart, batchPart, sectionPart, semPart] =
        selectedCourse.split(" | ");
      const [courseCode, ...courseNameArr] = codeNamePart.split(" - ");
      const courseName = courseNameArr.join(" - ");
      const batchName = batchPart?.replace("Batch: ", "").trim();
      const sectionName = sectionPart?.replace("Section: ", "").trim();
      const semester = semPart?.replace("Sem ", "").trim();

      const facultyUser = JSON.parse(localStorage.getItem("user") || "{}");
      // Combine firstName + lastName if present, otherwise fallback
      const facultyName =
        (facultyUser.firstName && facultyUser.lastName
          ? `${facultyUser.firstName} ${facultyUser.lastName}`
          : facultyUser.fullName || facultyUser.name || facultyUser.username) || "Faculty";

      const formData = new FormData();
      formData.append("facultyName", facultyName);
      formData.append("courseCode", courseCode);
      formData.append("courseName", courseName);
      formData.append("batchName", batchName);
      formData.append("sectionName", sectionName);
      formData.append("semester", semester);
      formData.append("taskTitle", taskTitle);
      formData.append("taskDescription", taskDescription);
      if (assignmentFile) formData.append("assignmentFile", assignmentFile);

      const res = await axios.post(
        "http://localhost:65000/api/faculty-tasks",
        formData,
        { headers: { "Content-Type": "multipart/form-data" } }
      );

      if (res.data.success) {
        toast.success("Task assigned successfully!");
        setTaskTitle("");
        setTaskDescription("");
        setAssignmentFile(null);
        setSelectedCourse("");
      } else {
        toast.error(res.data.message || "Failed to assign task");
      }
    } catch (err) {
      toast.error("Error submitting task: " + err.message);
    }
  };

  if (loading)
    return (
      <div style={{ padding: 40, textAlign: "center" }}>
        <h3>Loading courses...</h3>
      </div>
    );

  return (
    <div style={{ padding: 24, minHeight: "100vh", background: "#f9f9f9" }}>
      <ToastContainer position="top-right" autoClose={3000} />
      <Card
        title={<Title level={2}>Assign Task / Assignment</Title>}
        style={{ borderRadius: 12, boxShadow: "0 6px 15px rgba(0,0,0,0.1)" }}
      >
        <Form layout="vertical" onFinish={handleSubmit}>
          <Row gutter={[16, 16]}>
            <Col xs={24} md={12}>
              <Form.Item label="Select Course" required>
                <Select
                  placeholder="Select a course"
                  value={selectedCourse}
                  onChange={setSelectedCourse}
                  allowClear
                >
                  {courses.map((course) => (
                    <Option
                      key={course._id}
                      value={`${course.courseCode} - ${course.courseName} | Batch: ${course.batchName} | Section: ${course.sectionName} | Sem ${course.semester}`}
                    >
                      {course.courseCode} - {course.courseName} | Batch:{" "}
                      {course.batchName} | Section: {course.sectionName} | Sem{" "}
                      {course.semester}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col xs={24} md={12}>
              <Form.Item label="Task Title" required>
                <Input
                  placeholder="Enter task title"
                  value={taskTitle}
                  onChange={(e) => setTaskTitle(e.target.value)}
                />
              </Form.Item>
            </Col>
          </Row>

          <Form.Item label="Task Description" required>
            <TextArea
              placeholder="Enter task description"
              rows={4}
              value={taskDescription}
              onChange={(e) => setTaskDescription(e.target.value)}
            />
          </Form.Item>

          <Form.Item label="Upload Assignment File (optional)">
            <Upload
              beforeUpload={handleFileChange}
              onRemove={handleRemoveFile}
              fileList={assignmentFile ? [assignmentFile] : []}
            >
              <Button icon={<UploadOutlined />} style={{ borderRadius: 6 }}>
                Select File
              </Button>
            </Upload>
          </Form.Item>

          <Form.Item>
            <Button
              type="primary"
              htmlType="submit"
              style={{
                background: "linear-gradient(135deg, #8f7b99, #b2a4c2)",
                border: "none",
                fontWeight: 600,
                borderRadius: 6,
              }}
            >
              Assign Task
            </Button>
          </Form.Item>
        </Form>
      </Card>
    </div>
  );
};

export default FacultyTaskManager;
